parameters.jsCode:
// Compile weekly digest
const items = $input.all();
const traffic = items.find(i => i.json.total_sessions !== undefined)?.json || {};
const rankings = items.find(i => i.json.improved !== undefined)?.json || {};
const backlinks = items.find(i => i.json.new_backlinks !== undefined)?.json || {};
const alerts = items.find(i => i.json.critical !== undefined)?.json || {};

const weekEnd = new Date();
const weekStart = new Date(weekEnd);
weekStart.setDate(weekStart.getDate() - 7);

const digest = {
  period_start: weekStart.toISOString().split('T')[0],
  period_end: weekEnd.toISOString().split('T')[0],
  traffic: {
    sessions: traffic.total_sessions || 0,
    users: traffic.total_users || 0,
    pageviews: traffic.total_pageviews || 0,
    bounce_rate: Math.round((traffic.avg_bounce_rate || 0) * 100) / 100
  },
  rankings: {
    improved: rankings.improved || 0,
    declined: rankings.declined || 0,
    new: rankings.new_rankings || 0,
    lost: rankings.lost_rankings || 0
  },
  backlinks: {
    new: backlinks.new_backlinks || 0
  },
  alerts: {
    total: alerts.total || 0,
    critical: alerts.critical || 0,
    warning: alerts.warning || 0
  }
};

// Generate highlights
const highlights = [];
if (digest.rankings.improved > digest.rankings.declined) {
  highlights.push({ type: 'win', message: `Rankings improved: ${digest.rankings.improved} keywords up vs ${digest.rankings.declined} down` });
}
if (digest.backlinks.new > 0) {
  highlights.push({ type: 'win', message: `${digest.backlinks.new} new backlinks acquired` });
}
if (digest.alerts.critical > 0) {
  highlights.push({ type: 'alert', message: `${digest.alerts.critical} critical alerts require attention` });
}

digest.highlights = highlights;

return [{ json: digest }];

